-- ── VERIFICACIÓN FINAL ─────────────────────────────────────
SELECT
  status,
  COUNT(*) as total_leads,
  ROUND(AVG(confianza_nivel),1) as avg_confianza,
  ROUND(SUM(valor_estimado)/1e6,1) as valor_total_millones_mxn
FROM leads
WHERE empresa NOT IN ('FEMSA','Banorte','Walmart México')
GROUP BY status
ORDER BY
  CASE status
    WHEN 'nuevo' THEN 1 WHEN 'calificacion' THEN 2 WHEN 'contacto' THEN 3
    WHEN 'propuesta' THEN 4 WHEN 'negociacion' THEN 5 WHEN 'cierre' THEN 6
    WHEN 'postventa' THEN 7 WHEN 'retencion' THEN 8 WHEN 'fidelizacion' THEN 9
    WHEN 'cerrado_ganado' THEN 10 WHEN 'cerrado_perdido' THEN 11
  END;
